public boolean isValid(String date, String dateFormat) {
   boolean valid = false;
   if (date == null || date.isEmpty()) {
      valid = true;
   } else {
      try {
         LocalDate.parse(date, DateTimeFormatter.ofPattern(dateFormat).withResolverStyle(ResolverStyle.STRICT));
         valid = true;
      } catch (DateTimeParseException e) {
         valid = false;
      }
   }
   return valid;
}
